import React, { useState, useEffect } from "react";
import ReactDOM from "react-dom/client";
import {
  ArrowRight,
  ArrowLeft,
  Heart,
  Award,
  ChevronRight,
  ShieldCheck,
} from "lucide-react";
import "./Home.css";
import { useNavigate } from "react-router-dom";

// In a real project, these objects would be imported like: import styles from './Hero.module.css'

const commonStyles = {
  container: "layout_container",
  section: "layout_section",
  sectionBg: "layout_sectionBg",
  btnPrimary: "ui_btn ui_btnPrimary",
  btnOutline: "ui_btn ui_btnOutline",
  headerWrapper: "Header_wrapper",
  headerSubtitle: "Header_subtitle",
  headerTitle: "Header_title",
};

// --- Components ---

const SectionHeader = ({ title, subtitle }) => (
  <div className={commonStyles.headerWrapper}>
    <span className={commonStyles.headerSubtitle}>{subtitle}</span>
    <h2 className={commonStyles.headerTitle}>{title}</h2>
  </div>
);

const HeroSlider = () => {
  const navigate = useNavigate();
  // Module-like Styles definition
  const styles = {
    container: "Hero_container",
    slide: "Hero_slide",
    slideActive: "Hero_slideActive",
    bg: "Hero_bg",
    overlay: "Hero_overlay",
    content: "Hero_content",
    title: "Hero_title",
    highlight: "Hero_highlight",
    desc: "Hero_desc",
    actions: "Hero_actions",
    arrow: "Hero_arrow",
    arrowLeft: "Hero_arrowLeft",
    arrowRight: "Hero_arrowRight",
    dots: "Hero_dots",
    dot: "Hero_dot",
    dotActive: "Hero_dotActive",
  };

  const slides = [
    {
      id: 1,
      image: "/images/HomeSlider/HisteriaMaxBG2.webp",
      imageMobile: "/images/HomeSlider/HisteriaMaxMobileBG2.webp",
      title: "طعم يلامس الروح",
      highlight: "الروح",
      subtitle: "نصنع السعادة في كل قطعة، بمكونات طبيعية وشغف لا ينتهي.",
      ctaPrimary: "اكتشف منتجاتنا",
      path: "/Products",
      ctaSecondary: null,
    },
    {
      id: 2,
      image: "/images/HomeSlider/HugyMooshBG.webp",
      imageMobile: "/images/HomeSlider/HugyMooshMobileBG.webp",
      title: "جودة تستحق الثقة",
      highlight: "الثقة",
      subtitle: "أعلى معايير التصنيع العالمية لنقدم لكم الأفضل دائماً.",
      ctaPrimary: "من نحن",
      path: "/AboutUs",
      ctaSecondary: null,
    },
    {
      id: 3,
      image: "/images/HomeSlider/OpalizBG.webp",
      imageMobile: "/images/HomeSlider/OpalizMobileBG.webp",
      title: "لكل لحظة حكاية",
      highlight: "حكاية",
      subtitle: "شارك عائلتك وأصدقائك ألذ اللحظات مع تشكيلتنا المميزة.",
      ctaPrimary: "تواصل معنا",
      path: "/ContactUs",
      ctaSecondary: null,
    },
  ];

  const [current, setCurrent] = useState(0);

  const nextSlide = () => {
    setCurrent(current === slides.length - 1 ? 0 : current + 1);
  };

  const prevSlide = () => {
    setCurrent(current === 0 ? slides.length - 1 : current - 1);
  };

  useEffect(() => {
    const timer = setInterval(nextSlide, 5000);
    return () => clearInterval(timer);
  }, [current]);

  return (
    <div className={styles.container}>
      {slides.map((slide, index) => {
        const isActive = index === current;
        return (
          <div
            key={slide.id}
            className={`${styles.slide} ${isActive ? styles.slideActive : ""}`}
          >
            {/* 👇 الصورة */}
            <picture>
              <source media="(max-width: 768px)" srcSet={slide.imageMobile} />
              <img src={slide.image} alt={slide.title} className={styles.bg} />
            </picture>
            <div className={styles.overlay}>
              <div className={styles.content}>
                <h1 className={styles.title}>
                  {slide.title.replace(slide.highlight, "")}
                  <span className={styles.highlight}>{slide.highlight}</span>
                </h1>
                <p className={styles.desc}>{slide.subtitle}</p>
                <div className={styles.actions}>
                  {slide.ctaPrimary && (
                    <button
                      onClick={() => navigate(slide.path)}
                      className={commonStyles.btnPrimary}
                    >
                      {slide.ctaPrimary}
                    </button>
                  )}
                </div>
              </div>
            </div>
          </div>
        );
      })}

      <button
        className={`${styles.arrow} ${styles.arrowLeft}`}
        onClick={nextSlide}
      >
        <ArrowLeft size={24} />
      </button>
      <button
        className={`${styles.arrow} ${styles.arrowRight}`}
        onClick={prevSlide}
      >
        <ArrowRight size={24} />
      </button>

      <div className={styles.dots}>
        {slides.map((_, index) => (
          <div
            key={index}
            className={`${styles.dot} ${
              index === current ? styles.dotActive : ""
            }`}
            onClick={() => setCurrent(index)}
          ></div>
        ))}
      </div>
    </div>
  );
};

const Features = () => {
  // Module-like Styles definition
  const styles = {
    grid: "Features_grid",
    card: "Features_card",
    icon: "Features_icon",
    title: "Features_cardTitle",
    desc: "Features_cardDesc",
  };

  const features = [
    {
      icon: <Award size={32} />,
      title: "جودة عالمية",
      desc: "نلتزم بأدق معايير الجودة في كل خطوة من خطوات التصنيع.",
    },
    {
      icon: <Heart size={32} />,
      title: "صُنع بحب",
      desc: "كل منتج يخرج من مصنعنا يحمل معه شغف فريقنا وتفانيه.",
    },
    {
      icon: <ShieldCheck size={32} />,
      title: "سلامة مضمونة",
      desc: "أحدث التقنيات لضمان سلامة ونظافة منتجاتنا بنسبة 100%.",
    },
  ];

  return (
    <section className={`${commonStyles.section} ${commonStyles.sectionBg}`}>
      <div className={commonStyles.container}>
        <SectionHeader subtitle="لماذا بيسكوزا؟" title="تميز في كل تفصيل" />
        <div className={styles.grid}>
          {features.map((feature, idx) => (
            <div key={idx} className={styles.card}>
              <div className={styles.icon}>{feature.icon}</div>
              <h3 className={styles.title}>{feature.title}</h3>
              <p className={styles.desc}>{feature.desc}</p>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};

const Products = () => {
  const navigate = useNavigate();
  // Module-like Styles definition
  const styles = {
    grid: "Products_grid",
    card: "Products_card",
    img: "Products_img",
    overlay: "Products_overlay",
    title: "Products_title",
    action: "Products_action",
  };

  const categories = [
    {
      id: 1,
      title: "بسكويت",
      img: "/images/Product1/HisteriaMax2.webp",
      path: "/Biscuits",
    },
    {
      id: 2,
      title: "كيك",
      img: "/images/Product2/HugyMooshDark2.webp",
      path: "/Cake",
    },
  ];

  return (
    <section className={commonStyles.section}>
      <div className={commonStyles.container}>
        <SectionHeader subtitle="منتجاتنا" title="تشكيلة تناسب جميع الأذواق" />
        <div className={styles.grid}>
          {categories.map((category) => (
            <div
              key={category.id}
              className={styles.card}
              onClick={() => navigate(category.path)}
            >
              <img
                src={category.img}
                alt={category.title}
                className={styles.img}
              />
              <div className={styles.overlay}>
                <h3 className={styles.title}>{category.title}</h3>
                <div className={styles.action}>
                  تصفح المنتجات <ChevronRight size={20} />
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};

const Home = () => {
  return (
    <div className="app-root">
      <HeroSlider />
      <Features />
      <Products />
    </div>
  );
};

export default Home;
